import React, { useEffect, useState, useRef } from 'react';
import { Swiper, SwiperSlide } from 'swiper/react';
// Correct import for Swiper modules
import { Pagination, Navigation, Autoplay } from 'swiper/modules';
import 'swiper/css';
import 'swiper/css/pagination';
import 'swiper/css/navigation';
import '../styles/TestimonialsSection.css'; // Match your CSS file name exactly

const TestimonialsSection = () => { // Changed from TestimonialsPage to TestimonialsSection
    const [isVisible, setIsVisible] = useState(false);
    const sectionRef = useRef(null);

    useEffect(() => {
        const observer = new IntersectionObserver(
            ([entry]) => {
                if (entry.isIntersecting) {
                    setIsVisible(true);
                    observer.unobserve(entry.target);
                }
            },
            { threshold: 0.1 }
        );

        if (sectionRef.current) {
            observer.observe(sectionRef.current);
        }

        return () => {
            if (sectionRef.current) {
                observer.unobserve(sectionRef.current);
            }
        };
    }, []);

    return (
        <div ref={sectionRef} className={`testimonials-container ${isVisible ? 'visible' : ''}`}>
            <div className="testimonials-swiper-container">
                <Swiper
                    modules={[Pagination, Navigation, Autoplay]}
                    spaceBetween={30}
                    slidesPerView={1}
                    loop={true}
                    autoplay={{
                        delay: 5000,
                        disableOnInteraction: false,
                    }}
                    pagination={{
                        clickable: true,
                    }}
                    navigation={true}
                    className="testimonials-swiper"
                    breakpoints={{
                        640: {
                            slidesPerView: 1,
                        },
                        768: {
                            slidesPerView: 2,
                        },
                        1024: {
                            slidesPerView: 3,
                        },
                    }}
                >
                    {/* Testimonial 1 */}
                    <SwiperSlide>
                        <div className="testimonial-card">
                            <div className="quote-icon">
                                <span className="material-icons">format_quote</span>
                            </div>
                            <div className="testimonial-body">
                                <div className="course-tag">Web Development</div>
                                <p className="testimonial-text">
                                    "The practical approach at Forum Information Academy prepared me for real-world challenges. 
                                    Within a month of graduation, I secured a position at TechCorp where I'm using the exact 
                                    technologies I learned in the program."
                                </p>
                            </div>
                            <div className="testimonial-author">
                                <div className="testimonial-avatar">
                                    <img src="/images/testimonials/student1.jpg" alt="Yuki Tanaka" />
                                </div>
                                <div className="author-info">
                                    <h4>Yuki Tanaka</h4>
                                    <p>Software Engineer at TechCorp</p>
                                </div>
                            </div>
                        </div>
                    </SwiperSlide>

                    {/* Testimonial 2 */}
                    <SwiperSlide>
                        <div className="testimonial-card">
                            <div className="quote-icon">
                                <span className="material-icons">format_quote</span>
                            </div>
                            <div className="testimonial-body">
                                <div className="course-tag">Data Science</div>
                                <p className="testimonial-text">
                                    "I switched careers from finance to data science, which seemed daunting at first. 
                                    The curriculum was challenging but the instructors were incredibly supportive. 
                                    The career services team helped me prepare for interviews and showcase my new skills."
                                </p>
                            </div>
                            <div className="testimonial-author">
                                <div className="testimonial-avatar">
                                    <img src="/images/testimonials/student2.jpg" alt="Hana Kimura" />
                                </div>
                                <div className="author-info">
                                    <h4>Hana Kimura</h4>
                                    <p>Data Analyst at Global Insights</p>
                                </div>
                            </div>
                        </div>
                    </SwiperSlide>

                    {/* Testimonial 3 */}
                    <SwiperSlide>
                        <div className="testimonial-card">
                            <div className="quote-icon">
                                <span className="material-icons">format_quote</span>
                            </div>
                            <div className="testimonial-body">
                                <div className="course-tag">Cybersecurity</div>
                                <p className="testimonial-text">
                                    "The cybersecurity program at FIA was intensive and comprehensive. 
                                    We worked with real-world scenarios and the latest tools used in the industry. 
                                    My certification and portfolio projects helped me stand out in a competitive job market."
                                </p>
                            </div>
                            <div className="testimonial-author">
                                <div className="testimonial-avatar">
                                    <img src="/images/testimonials/student3.jpg" alt="Kenji Nakamura" />
                                </div>
                                <div className="author-info">
                                    <h4>Kenji Nakamura</h4>
                                    <p>Security Specialist at SecureNet</p>
                                </div>
                            </div>
                        </div>
                    </SwiperSlide>
                </Swiper>
            </div>
        </div>
    );
};

export default TestimonialsSection;
